sql:
SELECT * 
FROM ant_interactions 
WHERE attacker_type_id = 0;

SELECT ant_type_name 
FROM ant_types 
WHERE average_lifespan > 10;

SELECT colony_name, colony_size
FROM colonies
WHERE establishment_date = '2023-01-05';

external_knowledge:
- Confrontational interactions in the context of ants include predation;
- Social interactions refer to cooperative or communicative behaviors between different ant types;
- Ratios here denote the comparative numbers needed for one group to overpower another in the context of both types of interactions.

sql:
SELECT num_survivors, num_casualties 
FROM conflict_outcomes 
WHERE conflict_id = 1 AND ant_type_id = 1;

SELECT location, COUNT(colony_id) AS num_colonies
FROM colonies
GROUP BY location;

SELECT DISTINCT AT.ant_type_name, AT.average_lifespan
FROM ant_types AT
JOIN conflict_participants CP ON AT.ant_type_id = CP.ant_type_id;

SELECT cc.colony_id, a.ant_type_name, cc.population_count
FROM colony_composition AS cc
JOIN ant_types AS a ON cc.ant_type_id = a.ant_type_id;

SELECT DISTINCT colony_id, behavior_type
FROM colony_behavior
WHERE behavior_duration > 60 AND frequency > 4;

SELECT ant_type_id, MAX(num_survivors) 
FROM conflict_outcomes
GROUP BY ant_type_id;

SELECT AVG(average_lifespan)
FROM ant_types
WHERE ant_type_id IN (SELECT defender_type_id FROM ant_interactions);

SELECT ant_type_name
FROM ant_types
WHERE ant_type_id > 1;

SELECT COUNT(DISTINCT researcher_id) AS Num_Researchers
FROM data_access_logs
WHERE access_date BETWEEN '2023-01-01' AND '2023-12-31';

SELECT COUNT(DISTINCT colony_id) 
FROM colony_behavior 
WHERE behavior_type = 'Foraging';

SELECT interaction_id
FROM ant_interactions
LIMIT 5;

SELECT interaction_duration, interaction_outcome
FROM colony_interactions
WHERE interaction_type = 'Alliance' AND interaction_outcome = 'Alliance';

SELECT temperature, humidity, food_sources, predators, soil_type, water_sources
FROM colony_environment
WHERE environment_id = 0;

external_knowledge:
- 'Explorers' metaphorically refers to researchers;
- 'Vast ocean of data' represents the data access logs;
- 'More than a thousand voyages' symbolizes data access counts greater than 1000;
- In the domain of research, frequent data access might indicate active or persistent research work.

sql:
SELECT DISTINCT ant_type_name
FROM ant_types
WHERE ant_type_id IN (
    SELECT behavior_type 
    FROM colony_behavior
);

SELECT ant_type_name 
FROM ant_types 
WHERE average_lifespan = (SELECT MAX(average_lifespan) FROM ant_types);
